import React from 'react';
import { X, MapPin, Droplets, Image as ImageIcon, Clock } from 'lucide-react';

function toLatLng(report) {
  const lat = Number(report?.lat);
  const lng = Number(report?.lng);
  if (Number.isFinite(lat) && Number.isFinite(lng)) return { lat, lng };

  const coords = report?.location?.coordinates;
  if (Array.isArray(coords) && coords.length === 2) {
    const [cLng, cLat] = coords;
    if (Number.isFinite(cLat) && Number.isFinite(cLng)) return { lat: cLat, lng: cLng };
  }
  return null;
}

export default function ReportDetailsModal({ open, report, onClose }) {
  if (!open || !report) return null;

  const level = report.waterLevel || report.intensity || 'Low';
  const ll = toLatLng(report);
  const ts = report.createdAt || report.timestamp || report.time;

  return (
    <div className="fixed inset-0 z-[2000] grid place-items-center bg-black/60 p-4 backdrop-blur">
      <div className="w-full max-w-lg rounded-3xl border border-white/10 bg-slate-950 p-5 shadow-soft">
        <div className="flex items-start justify-between gap-4">
          <div>
            <div className="flex items-center gap-2 text-lg font-semibold">
              <Droplets size={18} className="text-sky-300" />
              Flood Report
            </div>
            <div className="mt-1 text-xs text-slate-400">Water level: {level}</div>
          </div>
          <button
            type="button"
            onClick={onClose}
            className="rounded-xl p-2 text-slate-300 hover:bg-white/5"
            aria-label="Close"
          >
            <X size={18} />
          </button>
        </div>

        <div className="mt-4 grid gap-3">
          {ll ? (
            <div className="rounded-2xl border border-white/10 bg-black/20 p-3 text-xs text-slate-300">
              <div className="flex items-center gap-2">
                <MapPin size={14} className="text-slate-400" />
                <span className="font-medium">Location</span>
                <span className="text-slate-400">
                  ({ll.lat.toFixed(6)}, {ll.lng.toFixed(6)})
                </span>
              </div>
              {report.address ? <div className="mt-1 text-[11px] text-slate-400">{report.address}</div> : null}
            </div>
          ) : null}

          {ts ? (
            <div className="rounded-2xl border border-white/10 bg-black/20 p-3 text-xs text-slate-300">
              <div className="flex items-center gap-2">
                <Clock size={14} className="text-slate-400" />
                <span className="font-medium">Time</span>
                <span className="text-slate-400">{new Date(ts).toLocaleString()}</span>
              </div>
            </div>
          ) : null}

          {report.imageUrl ? (
            <div className="rounded-2xl border border-white/10 bg-black/20 p-3">
              <div className="flex items-center gap-2 text-xs text-slate-300">
                <ImageIcon size={14} className="text-slate-400" />
                <span className="font-medium">Photo</span>
              </div>
              <img
                src={report.imageUrl}
                alt="Flood"
                className="mt-3 max-h-80 w-full rounded-2xl object-cover ring-1 ring-white/10"
              />
            </div>
          ) : (
            <div className="rounded-2xl border border-white/10 bg-black/20 p-3 text-xs text-slate-400">
              No photo for this report.
            </div>
          )}
        </div>
      </div>
    </div>
  );
}
